"""BalticSolar Alliance DAG namespace validation.

Runs in CI on every PR that adds or modifies a DAG file.
Rejects DAGs with non-conforming dag_id values before they
reach any Airflow instance.
"""
import re
from dataclasses import dataclass

ALLOWED_COUNTRIES = {'lt', 'lv', 'ee', 'eu'}
ALLOWED_TEAMS = {
    'de', 'analytics', 'ml', 'regulatory', 'platform',
    'battery', 'market',
}
ALLOWED_DOMAINS = {
    'meters', 'scada', 'weather', 'battery', 'generation',
    'regulatory', 'billing', 'market', 'alliance', 'platform',
}
ALLOWED_LAYERS = {'bronze', 'silver', 'gold', 'monitoring', 'maintenance'}

DAG_ID_PATTERN = re.compile(
    r'^(?P<country>[a-z]{2})_'
    r'(?P<team>[a-z]+)_'
    r'(?P<domain>[a-z]+)_'
    r'(?P<layer>[a-z]+)$'
)


@dataclass
class ValidationResult:
    dag_id: str
    valid: bool
    violations: list[str]


def validate_dag_id(dag_id: str) -> ValidationResult:
    """Validate a dag_id against the BalticSolar namespace convention."""
    violations = []

    match = DAG_ID_PATTERN.match(dag_id)
    if not match:
        violations.append(
            f"dag_id '{dag_id}' does not match pattern "
            f"'{{country}}_{{team}}_{{domain}}_{{layer}}'"
        )
        return ValidationResult(dag_id=dag_id, valid=False, violations=violations)

    country = match.group('country')
    team = match.group('team')
    domain = match.group('domain')
    layer = match.group('layer')

    if country not in ALLOWED_COUNTRIES:
        violations.append(f"Country '{country}' not in {ALLOWED_COUNTRIES}")
    if team not in ALLOWED_TEAMS:
        violations.append(f"Team '{team}' not in {ALLOWED_TEAMS}")
    if domain not in ALLOWED_DOMAINS:
        violations.append(f"Domain '{domain}' not in {ALLOWED_DOMAINS}")
    if layer not in ALLOWED_LAYERS:
        violations.append(f"Layer '{layer}' not in {ALLOWED_LAYERS}")

    # Cross-validation: coordinator DAGs must use 'eu' country
    if team == 'platform' and domain == 'alliance' and country != 'eu':
        violations.append("Alliance-wide DAGs must use country='eu'")

    if country == 'eu' and team != 'platform':
        violations.append("Only platform team can deploy DAGs with country='eu'")

    return ValidationResult(
        dag_id=dag_id, valid=len(violations) == 0, violations=violations,
    )

def create_dag(config: PipelineConfig) -> None:
    """Create and register an Airflow DAG from a pipeline configuration.

    This function is called once per YAML config file during DAG parsing.
    It creates a DAG with the standard BalticSolar task structure:
    ingest → validate → transform → quality_check → notify.
    """

    default_args = {
        'owner': config.owner_team,
        'retries': config.retries,
        'retry_delay': timedelta(seconds=config.retry_delay_seconds),
        'sla': timedelta(minutes=config.sla_minutes),
    }

    @dag(
        dag_id=config.dag_id,
        schedule=config.schedule,
        default_args=default_args,
        tags=[config.country, config.owner_team, config.domain,
              config.layer, f'factory:v{FACTORY_VERSION}'],
        catchup=False,
        max_active_runs=1,
        doc_md=f"""
        **Generated by BalticSolar DAG Factory v{FACTORY_VERSION}**

        Owner: {config.owner_team}
        Country: {config.country}
        Domain: {config.domain}
        Layer: {config.layer}
        SLA: {config.sla_minutes} minutes
        """,
    )
    def pipeline():
        # Standard task chain: ingest → validate → transform → check → notify

        @task
        def ingest_sources() -> dict:
            """Ingest data from all configured sources."""
            results = {}
            for source in config.sources:
                logger.info("Ingesting %s from %s", source.name, source.source_type)
                # Dispatch to source-type-specific ingestion logic
                results[source.name] = _ingest_source(source)
            return results

        @task
        def validate_schema(ingest_results: dict) -> dict:
            """Validate ingested data against the expected schema."""
            for source_name, result in ingest_results.items():
                source = next(s for s in config.sources if s.name == source_name)
                _validate_schema(result, source.schema_version)
            return ingest_results

        @task
        def transform(validated_data: dict) -> str:
            """Apply domain-specific transformations and write to target."""
            output_path = _transform_and_write(
                validated_data, config.target,
            )
            return output_path

        @task
        def quality_check(output_path: str) -> dict:
            """Run configured quality checks on the output."""
            results = {}
            for check in config.quality_checks:
                results[check['name']] = _run_quality_check(
                    output_path, check,
                )
            return results

        @task
        def notify(qc_results: dict) -> None:
            """Send notifications based on pipeline outcome."""
            if config.alerts:
                _send_notifications(config.dag_id, config.alerts, qc_results)

        data = ingest_sources()
        validated = validate_schema(data)
        output = transform(validated)
        qc = quality_check(output)
        notify(qc)

    pipeline()


# Factory version — embedded in every generated DAG's tags
# Enables tracking which factory version produced each DAG
FACTORY_VERSION = 3

"""Dynamic task generation for multi-source pipelines.

When a pipeline config specifies multiple sources, the factory
generates one task group per source with parallel execution,
followed by a merge task that combines the results.
"""
from __future__ import annotations

from airflow.decorators import task, task_group
from airflow.utils.task_group import TaskGroup


def create_dynamic_ingest(config: PipelineConfig):
    """Generate parallel ingestion task groups from config sources.

    Each source gets its own task group containing:
    ingest → validate_schema → log_metrics

    All task groups run in parallel. A downstream merge task
    waits for all groups to complete.
    """

    @task_group(group_id='ingest_sources')
    def ingest_all():
        results = {}

        for source in config.sources:
            @task_group(group_id=f'source_{source.name}')
            def process_source(src=source):

                @task(task_id=f'ingest_{src.name}',
                      pool=f'pool_{config.country}_ingestion')
                def ingest(source_config=src) -> dict:
                    """Ingest data from a single source."""
                    return _ingest_source(source_config)

                @task(task_id=f'validate_{src.name}')
                def validate(data: dict, source_config=src) -> dict:
                    """Validate schema for this source's data."""
                    _validate_schema(data, source_config.schema_version)
                    return data

                @task(task_id=f'metrics_{src.name}')
                def log_metrics(data: dict, source_config=src) -> None:
                    """Log ingestion metrics for monitoring."""
                    _log_source_metrics(
                        config.dag_id, src.name,
                        row_count=data.get('row_count', 0),
                    )

                raw = ingest()
                validated = validate(raw)
                log_metrics(validated)
                results[src.name] = validated

            process_source()

        return results

    return ingest_all()

"""Multi-country holiday-aware business day timetable.

Schedules DAGs on business days only, skipping weekends and
national holidays for the DAG's configured country. Holidays
are loaded from a shared calendar data source that is updated
annually by the regulatory compliance team.
"""
from __future__ import annotations

from datetime import date, datetime, timedelta
from typing import Any

from airflow.timetables.base import DagRunInfo, DataInterval, Timetable, TimeRestriction
from zoneinfo import ZoneInfo

from balticsolar_common.calendars import load_holidays


class BusinessDayTimetable(Timetable):
    """Schedule on business days, skipping weekends and holidays."""

    def __init__(self, country: str, run_time: str = '01:00', timezone: str = 'Europe/Vilnius'):
        super().__init__()
        self.country = country
        self.run_hour, self.run_minute = map(int, run_time.split(':'))
        self.tz = ZoneInfo(timezone)
        self._holidays: set[date] | None = None

    @property
    def holidays(self) -> set[date]:
        if self._holidays is None:
            self._holidays = load_holidays(self.country)
        return self._holidays

    def _is_business_day(self, d: date) -> bool:
        return d.weekday() < 5 and d not in self.holidays

    def _next_business_day(self, d: date) -> date:
        candidate = d + timedelta(days=1)
        while not self._is_business_day(candidate):
            candidate += timedelta(days=1)
        return candidate

    def next_dagrun_info(
        self,
        *,
        last_automated_data_interval: DataInterval | None,
        restriction: TimeRestriction,
    ) -> DagRunInfo | None:
        if last_automated_data_interval is None:
            # First run — find the next business day from today
            today = datetime.now(self.tz).date()
            next_bd = today if self._is_business_day(today) else self._next_business_day(today)
        else:
            # Subsequent run — find the next business day after the last interval
            last_date = last_automated_data_interval.end.date()
            next_bd = self._next_business_day(last_date)

        run_after = datetime(
            next_bd.year, next_bd.month, next_bd.day,
            self.run_hour, self.run_minute,
            tzinfo=self.tz,
        )

        if restriction.latest and run_after > restriction.latest:
            return None

        data_interval = DataInterval(
            start=run_after - timedelta(days=1),
            end=run_after,
        )
        return DagRunInfo(run_after=run_after, data_interval=data_interval)

    def serialize(self) -> dict[str, Any]:
        return {'country': self.country, 'run_time': f'{self.run_hour:02d}:{self.run_minute:02d}',
                'timezone': str(self.tz)}

    @classmethod
    def deserialize(cls, data: dict[str, Any]) -> 'BusinessDayTimetable':
        return cls(**data)

"""KubernetesExecutor pod cleanup for BalticSolar.

Completed pods accumulate in Kubernetes and consume etcd storage
and API server memory. This cleanup DAG runs hourly on the
Estonian instance to remove completed pods older than 2 hours.
"""
from __future__ import annotations

import logging
from datetime import datetime, timedelta, timezone

from airflow.decorators import dag, task
from airflow.providers.cncf.kubernetes.hooks.kubernetes import KubernetesHook

logger = logging.getLogger(__name__)

NAMESPACE = 'airflow-ee-workers'
MAX_POD_AGE = timedelta(hours=2)


@dag(
    dag_id='ee_platform_pods_maintenance',
    schedule='@hourly',
    catchup=False,
    tags=['ee', 'platform', 'maintenance'],
)
def pod_cleanup():

    @task
    def cleanup_completed_pods() -> dict:
        """Remove completed pods older than MAX_POD_AGE."""
        hook = KubernetesHook(conn_id='ee_kubernetes')
        client = hook.core_v1_client

        pods = client.list_namespaced_pod(
            namespace=NAMESPACE,
            field_selector='status.phase=Succeeded',
        )

        cutoff = datetime.now(timezone.utc) - MAX_POD_AGE
        deleted = 0
        errors = 0

        for pod in pods.items:
            if pod.status.start_time and pod.status.start_time < cutoff:
                try:
                    client.delete_namespaced_pod(
                        name=pod.metadata.name,
                        namespace=NAMESPACE,
                    )
                    deleted += 1
                except Exception as e:
                    logger.warning("Failed to delete pod %s: %s", pod.metadata.name, e)
                    errors += 1

        logger.info(
            "Pod cleanup: deleted=%d errors=%d remaining=%d",
            deleted, errors, len(pods.items) - deleted,
        )
        return {'deleted': deleted, 'errors': errors}

    @task
    def check_resource_quota() -> dict:
        """Check namespace resource quota utilization."""
        hook = KubernetesHook(conn_id='ee_kubernetes')
        client = hook.core_v1_client

        quotas = client.list_namespaced_resource_quota(namespace=NAMESPACE)
        for quota in quotas.items:
            used = quota.status.used or {}
            hard = quota.status.hard or {}
            for resource, limit in hard.items():
                current = used.get(resource, '0')
                logger.info(
                    "Resource quota %s: %s / %s",
                    resource, current, limit,
                )
        return {'quotas_checked': len(quotas.items)}

    cleanup_completed_pods() >> check_resource_quota()

pod_cleanup()

"""Hybrid executor routing in BalticSolar DAG factory.

The factory assigns each task to the correct executor backend
based on the task type specified in the pipeline config.
"""
from __future__ import annotations

from airflow.decorators import task


# KubernetesExecutor pod override for heavy tasks
HEAVY_TASK_POD_OVERRIDE = {
    'spec': {
        'containers': [{
            'name': 'base',
            'resources': {
                'requests': {'memory': '8Gi', 'cpu': '2000m'},
                'limits': {'memory': '32Gi', 'cpu': '8000m'},
            },
            'volumeMounts': [{
                'name': 'scratch',
                'mountPath': '/tmp/scratch',
            }],
        }],
        'volumes': [{
            'name': 'scratch',
            'emptyDir': {'sizeLimit': '50Gi'},
        }],
    },
}


@task(
    queue='kubernetes',
    executor_config={
        'pod_override': HEAVY_TASK_POD_OVERRIDE,
    },
)
def submit_spark_transform(config: dict) -> str:
    """Submit a Spark transformation job.

    Runs in a dedicated Kubernetes pod with 8-32 GB memory
    and 50 GB scratch storage. The pod is created when the
    task starts and destroyed when it completes.
    """
    from balticsolar_common.spark import submit_spark_job

    job_result = submit_spark_job(
        application=config['spark_app'],
        arguments=config['spark_args'],
        driver_memory='4g',
        executor_memory='8g',
        num_executors=4,
    )
    return job_result['output_path']


@task(queue='queue_gold')  # Goes to CeleryExecutor
def update_dataset_registry(output_path: str) -> None:
    """Update the Dataset registry after Spark job completes.

    Lightweight task — runs on a Celery worker with sub-second
    startup. No need for Kubernetes pod isolation.
    """
    from balticsolar_common.datasets import notify_dataset_ready

    notify_dataset_ready(
        dataset_uri=f's3://balticsolar-lv/silver/meters/',
        metadata={'output_path': output_path},
    )

