"""Contract validation tests for BalticSolar integrations.

Verifies that each hook's actual behavior matches its
declared contract (the YAML file from lesson 3).
"""
import pytest
import yaml

from balticsolar_provider.hooks.nordpool import NordPoolHook


class TestNordPoolContract:
    """Validate NordPoolHook against nordpool-market-api.yaml contract."""

    @pytest.fixture
    def contract(self):
        with open('balticsolar_provider/contracts/nordpool-market-api.yaml') as f:
            return yaml.safe_load(f)

    @pytest.fixture
    def hook(self, mock_nordpool_connection):
        return NordPoolHook(nordpool_conn_id='test_nordpool')

    def test_get_day_ahead_prices_returns_contract_fields(
        self, hook, contract, mock_nordpool_api,
    ):
        """Verify output fields match contract specification."""
        from datetime import datetime

        result = hook.get_day_ahead_prices(
            delivery_date=datetime(2026, 3, 24),
            area='LT',
        )

        # Contract defines output fields
        expected_fields = {
            f['name'] if isinstance(f, dict) else f.split(':')[0].strip()
            for f in contract['interface']['methods']
            ['get_day_ahead_prices']['output']['fields']
        }

        assert len(result) > 0
        actual_fields = set(result[0].keys())
        # Actual output must contain all contracted fields
        missing = expected_fields - actual_fields
        assert not missing, f"Missing contracted fields: {missing}"

    def test_transient_errors_are_retriable(
        self, hook, contract, mock_nordpool_api_429,
    ):
        """Verify that transient errors (429) raise retriable exceptions."""
        from requests.exceptions import HTTPError

        with pytest.raises(HTTPError) as exc_info:
            hook.get_day_ahead_prices(
                delivery_date=datetime(2026, 3, 24),
                area='LT',
            )
        # 429 is classified as transient in the contract
        assert exc_info.value.response.status_code == 429

    def test_permanent_errors_fail_immediately(
        self, hook, contract, mock_nordpool_api_401,
    ):
        """Verify that permanent errors (401) are not retried."""
        from balticsolar_provider.hooks._base import PermanentIntegrationError

        with pytest.raises(PermanentIntegrationError):
            hook.get_day_ahead_prices(
                delivery_date=datetime(2026, 3, 24),
                area='LT',
            )

"""DAG-level access control in BalticSolar DAG factory.

The factory sets access_control on every generated DAG based on
the config's owner_team field. This ensures that DAG visibility
and permissions are automatically aligned with the namespace
convention and ownership registry.
"""
from __future__ import annotations

from airflow.decorators import dag


def create_dag_with_access_control(config):
    """Factory wrapper that adds access_control based on ownership."""

    # Map owner_team to RBAC role names
    TEAM_TO_ROLES = {
        'lt-data-engineering': {
            'lt_operator': {'can_dag_read', 'can_dag_edit'},
        },
        'lv-data-engineering': {
            'lv_operator': {'can_dag_read', 'can_dag_edit'},
        },
        'ee-data-engineering': {
            'ee_operator': {'can_dag_read', 'can_dag_edit'},
        },
        'platform-engineering': {
            'alliance_admin': {'can_dag_read', 'can_dag_edit'},
        },
        'lt-analytics': {
            'lt_analyst': {'can_dag_read'},           # read-only for analysts
            'lt_operator': {'can_dag_read', 'can_dag_edit'},  # operators can edit
        },
    }

    # Every DAG is visible to alliance_admin and alliance_viewer
    access = {
        'alliance_admin': {'can_dag_read', 'can_dag_edit'},
        'alliance_viewer': {'can_dag_read'},
    }

    # Add team-specific access
    team_access = TEAM_TO_ROLES.get(config.owner_team, {})
    access.update(team_access)

    @dag(
        dag_id=config.dag_id,
        schedule=config.schedule,
        access_control=access,
        # ... remaining DAG parameters from factory
    )
    def pipeline():
        pass

    pipeline()

# vault-policy-lt-airflow.hcl
# Policy for the Lithuanian Airflow instance's Vault token.
# Grants read access to Lithuanian secrets and shared secrets only.

# Lithuanian country secrets — read-only
path "secret/data/balticsolar/lt/*" {
  capabilities = ["read", "list"]
}

# Shared secrets (Nord Pool, ENTSO-E, weather) — read-only
path "secret/data/balticsolar/shared/*" {
  capabilities = ["read", "list"]
}

# Explicitly deny access to other countries' secrets
# (redundant with the absence of a grant, but makes intent explicit)
path "secret/data/balticsolar/lv/*" {
  capabilities = ["deny"]
}

path "secret/data/balticsolar/ee/*" {
  capabilities = ["deny"]
}

# Allow the instance to renew its own token
path "auth/token/renew-self" {
  capabilities = ["update"]
}
